sys_script.script:
(function executeRule(current, previous) {

    var ciSysId = current.cmdb_ci.toString();
    if (!ciSysId) return;

    // Check if any other active signals still exist for this CI
    var activeSignals = new GlideRecord('pa_kpi_signal');
    activeSignals.addQuery('cmdb_ci', ciSysId);
    activeSignals.addQuery('active', true);
    activeSignals.addQuery('sys_id', '!=', current.sys_id);
    activeSignals.query();

    if (activeSignals.hasNext()) {
        // Other breaches still active — re-evaluate state downward only
        var engine   = new ServiceStateEngine(ciSysId);
        var eventGr  = new GlideRecord('u_anomaly_event');
        eventGr.addQuery('u_configuration_item', ciSysId);
        eventGr.addQuery('u_active', true);
        eventGr.setLimit(1);
        eventGr.query();

        if (eventGr.next()) {
            var newState = engine.evaluateTransition(eventGr.u_state.toString());
            eventGr.u_state             = newState;
            eventGr.u_last_evaluated_on = new GlideDateTime();
            eventGr.update();
        }
        return;
    }

    // All signals resolved — close anomaly event
    var resolveGr = new GlideRecord('u_anomaly_event');
    resolveGr.addQuery('u_configuration_item', ciSysId);
    resolveGr.addQuery('u_active', true);
    resolveGr.query();

    while (resolveGr.next()) {
        resolveGr.u_active       = false;
        resolveGr.u_state        = 1; // Normal
        resolveGr.u_resolved_on  = new GlideDateTime();
        resolveGr.update();
        gs.info('SignalResolutionBridge: Anomaly event resolved for CI ' + ciSysId);
    }

})(current, previous);
